function formatSearchSection(tag, entry, affiliate, filters) {
  const lines = [];
  lines.push(`### ${tag}`);
  lines.push("");
  lines.push(`> ${entry.query} \xB7 ${new Date(entry.timestamp).toLocaleString()}`);
  lines.push("");
  lines.push("| ID | Price | Stops | Duration | Carrier | Date | Dep\u2192Arr |");
  lines.push("|----|------:|-------|----------|---------|------|---------|");
  for (const o of entry.offers.slice(0, 10)) {
    const arr = `${o.arrival}${o.arrival_time_ahead}`;
    lines.push(`| ${o.id} | ${o.price} | ${stopsLabel2(o.stops)} | ${o.duration} | ${o.name} | ${o.departure_date} | ${o.departure}\u2192${arr} |`);
  }
  if (entry.offers.length > 10)
    lines.push(`
*\u2026and ${entry.offers.length - 10} more results*`);
  const cheapest = entry.offers[0];
  if (cheapest) {
    const bookLinks = offerBookingLinks(cheapest, affiliate, filters ?? (entry.params ? toBookingFilters(entry.params) : undefined));
    if (bookLinks.length) {
      lines.push("");
      lines.push("**Book this route:**");
      lines.push(...bookLinks);
    }
  }
  return lines.join(`
`);
}
function buildMarkdown(searches, itineraries, opts) {
  const sections = [];
  const heading = opts.title ?? "Flight Search Results";
  const date = new Date().toISOString().slice(0, 10);
  sections.push(`# ${heading}`);
  sections.push(`*Generated ${date}*`);
  if (itineraries.length > 0) {
    sections.push(`
## Recommended Options
`);
    for (const itin of itineraries)
      sections.push(formatItinerary(itin, opts.affiliate));
  }
  if (searches.length > 0) {
    sections.push(`
## All Searches
`);
    for (const [tag, entry] of searches) {
      sections.push(formatSearchSection(tag, entry, opts.affiliate, opts.filters));
      sections.push("");
    }
  }
  return sections.join(`
`);
}
