function uniqueLegs(offers) {
  const seen = new Set;
  return offers.flatMap((o) => o.legs.filter((l) => {
    const key = `${l.departure_airport}-${l.arrival_airport}`;
    if (seen.has(key))
      return false;
    seen.add(key);
    return true;
  }));
}
function offerRoute(o) {
  const from = o.legs[0]?.departure_airport ?? "?";
  const to = o.legs[o.legs.length - 1]?.arrival_airport ?? "?";
  return `${from} > ${to}`;
}
async function generatePdf(opts) {
  const doc = new import_jspdf.jsPDF({ orientation: "landscape", unit: "mm", format: "a4" });
  const W = doc.internal.pageSize.getWidth();
  const H = doc.internal.pageSize.getHeight();
  doc.setFont(FONT);
  fillPage(doc, W, H);
  let cy = 14;
  doc.setFontSize(18);
  doc.setTextColor(AMBER);
  doc.text(opts.title ?? "FLIGHT SEARCH RESULTS", W / 2, cy, { align: "center" });
  cy += 6;
  doc.setFontSize(9);
  doc.setTextColor(MUTED);
  doc.text(new Date().toLocaleDateString("en-US", { dateStyle: "long" }), W / 2, cy, {
    align: "center"
  });
  cy += 6;
  const allOffers = opts.searches.flatMap(([, e]) => e.offers);
  const legs = uniqueLegs(allOffers);
  if (legs.length > 0) {
    const mapW = Math.min(240, W - 20);
    drawRouteMap(doc, legs, (W - mapW) / 2, cy, mapW, 55);
    cy += 60;
  }
  const top = allOffers.slice(0, 15);
  if (top.length > 0) {
    autoTable(doc, {
      startY: cy,
      margin: { left: 10, right: 10 },
      head: [["#", "Price", "Carrier", "Route", "Date", "Dep > Arr", "Duration", "Stops"]],
      body: top.map((o, i) => [
        String(i + 1),
        o.price,
        o.name,
        offerRoute(o),
        o.departure_date,
        `${o.departure} > ${o.arrival}`,
        o.duration,
        fmtStops(o.stops)
      ]),
      ...tableTheme()
    });
  }
  for (const itin of opts.itineraries) {
    renderItinerary(doc, itin, opts.affiliate, opts.filters, W, H);
  }
  return Buffer.from(doc.output("arraybuffer"));
}
function renderItinerary(doc, it, affiliate, filters, W, H) {
  doc.addPage();
  fillPage(doc, W, H);
  let cy = 14;
  doc.setFont(FONT);
  doc.setFontSize(14);
  doc.setTextColor(AMBER);
  doc.text(it.title.toUpperCase(), W / 2, cy, { align: "center" });
  cy += 8;
  const legs = uniqueLegs(it.legs);
  if (legs.length > 0) {
    const mapW = Math.min(200, W - 20);
    drawRouteMap(doc, legs, (W - mapW) / 2, cy, mapW, 45);
    cy += 50;
  }
  autoTable(doc, {
    startY: cy,
    margin: { left: 10, right: 10 },
    head: [["#", "Price", "Carrier", "Route", "Date", "Dep > Arr", "Duration", "Stops"]],
    body: it.legs.map((o, i) => [
      String(i + 1),
      o.price,
      o.name,
      offerRoute(o),
      o.departure_date,
      `${o.departure} > ${o.arrival}`,
      o.duration,
      fmtStops(o.stops)
    ]),
    ...tableTheme()
  });
  const lastY = doc.lastAutoTable?.finalY ?? cy + 30;
  let linkY = lastY + 8;
  doc.setFontSize(8);
  doc.setTextColor(MUTED);
  doc.text("BOOKING LINKS", 10, linkY);
  linkY += 5;
  for (const offer of it.legs) {
    const urls = buildOfferBookingUrls(offer, affiliate, it.filters ?? filters);
    if (!urls)
      continue;
    for (const [program, url] of Object.entries(urls)) {
      const label = `${offerRoute(offer)} - ${PROGRAM_LABELS[program] ?? program}`;
      doc.setTextColor(AMBER);
      doc.textWithLink(label, 10, linkY, { url });
      linkY += 4.5;
    }
  }
}
function buildOfferBookingUrls(offer, affiliate, filters) {
  if (!affiliate)
    return null;
  const from = resolveIata(offer.legs[0]?.departure_airport ?? "");
  const to = resolveIata(offer.legs[offer.legs.length - 1]?.arrival_airport ?? "");
  if (!from || !to)
    return null;
  return buildBookingUrls(affiliate, {
    from_airport: from,
    to_airport: to,
    date: offer.departure_date,
    return_date: offer.return_date ?? undefined
  }, filters);
}
function tableTheme() {
  return {
    styles: {
      font: FONT,
      fontSize: 7,
      textColor: TEXT,
      fillColor: BG2,
      lineColor: "#2d333b",
      lineWidth: 0.2,
      cellPadding: 2
    },
    headStyles: {
      fillColor: SURFACE,
      textColor: AMBER,
      fontSize: 7,
      fontStyle: "normal"
    },
    alternateRowStyles: { fillColor: SURFACE },
    theme: "grid"
  };
}
function fillPage(doc, W, H) {
  doc.setFillColor(BG2);
  doc.rect(0, 0, W, H, "F");
}

// src/commands/takeout.ts
function parseOneItin(raw, start) {
  const title = raw[start] ?? "Untitled";
  const refs = [];
  let i = start + 1;
  while (i < raw.length && !raw[i].startsWith("--"))
    refs.push(raw[i++]);
  let note;
  if (raw[i] === "--note") {
    note = raw[++i];
    i++;
  }
  return { itin: { title, note, legs: refs }, next: i };
}
function parseItineraryArgs(raw) {
  const itineraries = [];
  let i = 0;
  while (i < raw.length) {
    if (raw[i] !== "--itin") {
      i++;
      continue;
    }
    const { itin, next } = parseOneItin(raw, i + 1);
    itineraries.push(itin);
    i = next;
  }
  return itineraries;
}
var takeoutCommand = defineCommand({
  meta: {
    name: "takeout",
    description: "Export search results and itineraries to markdown or PDF"
  },
  args: {
    output: {
      type: "string",
      alias: "o",
      description: "Output file path (default: ~/Desktop/flights-<date>.<ext>)"
    },
    title: { type: "string", description: "Document title" },
    pdf: {
      type: "boolean",
      description: "Export as PDF instead of markdown",
      default: false
    },
    "keep-session": {
      type: "boolean",
      description: "Keep session open after export (default: closes it)",
      default: false
    }
  },
  async run({ args }) {
    const session = await loadSession();
    if (!session) {
      console.log(formatError("NO_SESSION", "No search results cached. Run `flt search` first."));
      return;
    }
    const rawArgs = process.argv.slice(2);
    const itinDefs = parseItineraryArgs(rawArgs);
    const itineraries = [];
    for (const def of itinDefs) {
      const legs = [];
      for (const ref of def.legs) {
        const offer = await resolveOffer(session, ref);
        if (!offer) {
          console.log(formatError("NOT_FOUND", `Offer '${ref}' not found in session.`));
          return;
        }
        legs.push(offer);
      }
      const firstRef = def.legs[0];
      const searchRef = firstRef?.includes(":") ? firstRef.split(":")[0] : undefined;
      const refEntry = searchRef ? await loadSearchByRef(session, searchRef) : null;
      itineraries.push({ title: def.title, note: def.note, legs, filters: refEntry?.params });
    }
    const searches = await loadSessionScopedSearches(session);
    const config = await loadConfig();
    const affiliate = config.marker && config.trs ? { marker: config.marker, trs: config.trs } : null;
    const now = new Date;
    const date = now.toISOString().slice(0, 10);
    const time = now.toTimeString().slice(0, 5).replace(":", "");
    const ext = args.pdf ? "pdf" : "md";
    const defaultPath = join3(process.env.HOME ?? ".", "Desktop", `flights-${date}-${time}.${ext}`);
    const outPath = args.output ?? defaultPath;
    if (args.pdf) {
      const buf = await generatePdf({ searches, itineraries, affiliate, title: args.title });
      await writeFile3(outPath, buf);
    } else {
      const md = buildMarkdown(searches, itineraries, { affiliate, title: args.title });
      await writeFile3(outPath, md, "utf-8");
    }
    console.log(JSON.stringify({
      ok: true,
      path: outPath,
      searches: searches.length,
      itineraries: itineraries.length
    }));
    const active = getActiveSession(session);
    if (active && !args["keep-session"]) {
      closeActiveSession(session);
      await saveSession(session);
      console.error(`[session] Closed "${active.name}" (${active.id}). Use \`flt session reopen\` to re-open, or \`--keep-session\` next time.`);
    }
  }
});

// src/index.ts
var SUB_COMMANDS = {
  search: searchCommand,
  inspect: inspectCommand,
  itinerary: itineraryCommand,
  matrix: matrixCommand,
  airports: airportsCommand,
  prime: primeCommand,
  takeout: takeoutCommand,
  session: sessionCommand,
  config: configCommand,
  connections: connectionsCommand,
  fav: favCommand,
  unfav: unfavCommand,
  favs: favsCommand
};
var DATE_RE = /^\d{4}-\d{2}-\d{2}$/;
var FLEX_DATE = /^\d{1,2}\/\d{1,2}\/\d{4}$|^(today|tomorrow|overmorrow)$/i;
var main = defineCommand({
  meta: { name: "flt", version: "0.1.0", description: "Flight search CLI" },
  subCommands: SUB_COMMANDS
});
var args = process.argv.slice(2);
var first = args[0];
if (!first || first.startsWith("-")) {
  await showUsage(main);
} else if (first in SUB_COMMANDS) {
  runMain(main);
} else if (first.match(/^F[0-9a-f]{4,}$/i)) {
  runCommand(inspectCommand, { rawArgs: args });
} else if (args.length >= 3 && (DATE_RE.test(args[2]) || FLEX_DATE.test(args[2]))) {
  runCommand(searchCommand, { rawArgs: args });
} else {
  runCommand(airportsCommand, { rawArgs: [args[0], "--limit", "5"] });
}
